import mysql.connector

def import_data_with_load_data_infile(db_config, file_path, table_name, fields_terminated_by=',', lines_terminated_by='\n', enclosed_by='"', optionally_enclosed=False, ignore_lines=1):
    """
    Imports data from a CSV file into a MySQL table using LOAD DATA INFILE.

    Args:
        db_config (dict): A dictionary containing database connection details
                          (e.g., 'host', 'user', 'v_password', 'database').
        file_path (str): The absolute path to the CSV file to import.
        table_name (str): The name of the target table in the database.
        fields_terminated_by (str): The character that separates fields. Default is ','.
        lines_terminated_by (str): The character that separates lines. Default is '\n'.
        enclosed_by (str): The character that encloses fields. Default is '"'.
        optionally_enclosed (bool): Whether fields are optionally enclosed. Default is False.
        ignore_lines (int): Number of lines to ignore at the beginning of the file. Default is 1 (for headers).
    """
    conn = None
    try:
        # Establish connection with local_infile=True
        conn = mysql.connector.connect(**db_config, local_infile=True)
        cursor = conn.cursor()

        # Construct the LOAD DATA INFILE statement
        load_data_sql = f"""
        LOAD DATA INFILE '{file_path}'
        INTO TABLE {table_name}
        FIELDS TERMINATED BY '{fields_terminated_by}'
        {'OPTIONALLY' if optionally_enclosed else ''} ENCLOSED BY '{enclosed_by}'
        LINES TERMINATED BY '{lines_terminated_by}'
        IGNORE {ignore_lines} LINES;
        """

        print(f"Executing: {load_data_sql}")
        cursor.execute(load_data_sql)
        conn.commit()
        print(f"Successfully imported data from '{file_path}' into table '{table_name}'.")

    except mysql.connector.Error as err:
        print(f"Error: {err}")
        if conn and conn.is_connected():
            conn.rollback() # Rollback in case of error
    finally:
        if conn and conn.is_connected():
            cursor.close()
            conn.close()
            print("MySQL connection closed.")

